import type {GenogramSymbolType} from "@/core/domain/genogram.ts";
import {symbolToSex} from "@/core/domain/genogram-symbols.ts";
import type {XYPosition} from "@xyflow/react";
import { v4 as uuid } from 'uuid';
import {SYMBOL_NODE_TYPE_MAP, type GenogramNodeBySymbol, type NodeTypeForSymbol} from "@/features/diagram/types/nodes.ts";

type NodeFactory<S extends GenogramSymbolType> = (position: XYPosition) => GenogramNodeBySymbol<S>;

export const createNodeFactory = <S extends GenogramSymbolType>(symbol: S): NodeFactory<S> => {
    return (position: XYPosition) => {
        const id = uuid();
        const type = SYMBOL_NODE_TYPE_MAP[symbol] as NodeTypeForSymbol<S>;

        return {
            id,
            type,
            position,
            data: {
                uid: id,
                callSign: '',
                sex: symbolToSex(symbol),
                symbol,
                deceased: false
            }
        } as GenogramNodeBySymbol<S>;
    };
};

export const createNewNode = <S extends GenogramSymbolType>(symbol: S, position: XYPosition): GenogramNodeBySymbol<S> => {
    return createNodeFactory(symbol)(position);
};

import type {GenogramSymbolType} from "@/core/domain/genogram.ts";
import {symbolToSex} from "@/core/domain/genogram-symbols.ts";
import type {XYPosition} from "@xyflow/react";
import { v4 as uuid } from 'uuid';
import {SYMBOL_NODE_TYPE_MAP, type GenogramNodeBySymbol, type NodeTypeForSymbol} from "@/features/diagram/types/nodes.ts";

type NodeFactory<S extends GenogramSymbolType> = (position: XYPosition) => GenogramNodeBySymbol<S>;

export const createNodeFactory = <S extends GenogramSymbolType>(symbol: S): NodeFactory<S> => {
    return (position: XYPosition) => {
        const id = uuid();
        const type = SYMBOL_NODE_TYPE_MAP[symbol] as NodeTypeForSymbol<S>;

        return {
            id,
            type,
            dragHandle: '.drag-handle',
            position,
            data: {
                uid: id,
                callSign: '',
                sex: symbolToSex(symbol),
                symbol,
                deceased: false
            }
        } as GenogramNodeBySymbol<S>;
    };
};

export const createNewNode = <S extends GenogramSymbolType>(symbol: S, position: XYPosition): GenogramNodeBySymbol<S> => {
    return createNodeFactory(symbol)(position);
};

import React from "react";
import type {Person} from "@/core/domain/genogram.ts";
import type {Node, NodeProps} from '@xyflow/react';
import {useReactFlow} from '@xyflow/react';
import {IconCake, IconCross} from '@tabler/icons-react';
import {Box, Group, Stack, Text, TextInput, Textarea} from '@mantine/core';
import {SymbolIcon} from "@/core/ui/icons/SymbolIcons.tsx";
import type {GenogramEdge} from "@/features/diagram/types/edges.tsx";
import type {GenogramNode} from "@/features/diagram/types/nodes.ts";

import nodeClasses from './nodes.module.css';

type PersonNode = Node<Person, "person" | "pregnancy" | "loss" | "pet">;

const clampToLines = (value: string, maxLines = 3): string => value.split(/\r?\n/).slice(0, maxLines).join('\n');

const ISO_DATE_RE = /^(\d{4})-(\d{2})-(\d{2})$/;
const DISPLAY_DATE_RE = /^(\d{2})-(\d{2})-(\d{4})$/;

const normalizeDateInput = (value: string): string => {
    const digits = value.replace(/\D/g, '').slice(0, 8);
    if (digits.length <= 2) return digits;
    if (digits.length <= 4) return `${digits.slice(0, 2)}-${digits.slice(2)}`;
    return `${digits.slice(0, 2)}-${digits.slice(2, 4)}-${digits.slice(4)}`;
};

const toDisplayDate = (value?: string): string => {
    if (!value) return '';
    const trimmed = value.trim();
    const display = trimmed.match(DISPLAY_DATE_RE);
    if (display) return trimmed;

    const iso = trimmed.match(ISO_DATE_RE);
    if (!iso) return trimmed;
    return `${iso[3]}-${iso[2]}-${iso[1]}`;
};

const parseDate = (value?: string): Date | null => {
    if (!value) return null;
    const trimmed = value.trim();

    const display = trimmed.match(DISPLAY_DATE_RE);
    if (display) {
        const day = Number(display[1]);
        const month = Number(display[2]);
        const year = Number(display[3]);
        const date = new Date(year, month - 1, day);
        if (date.getFullYear() === year && date.getMonth() === month - 1 && date.getDate() === day) return date;
        return null;
    }

    const iso = trimmed.match(ISO_DATE_RE);
    if (iso) {
        const year = Number(iso[1]);
        const month = Number(iso[2]);
        const day = Number(iso[3]);
        const date = new Date(year, month - 1, day);
        if (date.getFullYear() === year && date.getMonth() === month - 1 && date.getDate() === day) return date;
    }

    return null;
};

const calculateAge = (birthDate?: string, deathDate?: string): string => {
    if (!birthDate) return '-';

    const birth = parseDate(birthDate);
    if (!birth) return '-';

    const end = deathDate ? parseDate(deathDate) : new Date();
    if (!end || end < birth) return '-';

    let years = end.getFullYear() - birth.getFullYear();
    const monthDelta = end.getMonth() - birth.getMonth();
    const dayDelta = end.getDate() - birth.getDate();

    if (monthDelta < 0 || (monthDelta === 0 && dayDelta < 0)) years -= 1;
    return `${Math.max(0, years)}`;
};

export const PersonNode: React.FC<NodeProps<PersonNode>> = ({id, data}) => {
    const {setNodes} = useReactFlow<GenogramNode, GenogramEdge>();
    const [name, setName] = React.useState(data.callSign ?? '');
    const [birthDate, setBirthDate] = React.useState(toDisplayDate(data.birthDate));
    const [deathDate, setDeathDate] = React.useState(toDisplayDate(data.deathDate));

    React.useEffect(() => {
        setName(data.callSign ?? '');
        setBirthDate(toDisplayDate(data.birthDate));
        setDeathDate(toDisplayDate(data.deathDate));
    }, [data.callSign, data.birthDate, data.deathDate]);

    const updateData = React.useCallback((patch: Partial<Person>) => {
        setNodes((currentNodes) => currentNodes.map((node) => {
            if (node.id !== id) return node;
            return {
                ...node,
                data: {
                    ...node.data,
                    ...patch
                }
            } as GenogramNode;
        }));
    }, [id, setNodes]);

    return (
        <div className={nodeClasses.card}>
            <Stack gap={1}>
                <Group wrap="nowrap" align="flex-start" gap={10}>
                    <Box w={42} miw={42} pt={2} style={{display: 'flex', justifyContent: 'center'}}>
                        <SymbolIcon symbol={data.symbol} deceased={data.deceased} size={34}/>
                    </Box>

                    <Textarea
                        value={name}
                        onChange={(event) => {
                            const next = clampToLines(event.target.value, 3);
                            setName(next);
                            updateData({callSign: next});
                        }}
                        placeholder="Name"
                        variant="unstyled"
                        minRows={3}
                        maxRows={3}
                        autosize
                        classNames={{
                            input: 'nodrag nowheel'
                        }}
                        styles={{
                            root: {flex: 1, minWidth: 0},
                            input: {
                                fontSize: '13px',
                                fontWeight: 600,
                                lineHeight: 1.15,
                                color: '#1f2937',
                                padding: 0
                            }
                        }}
                    />
                </Group>

                <Group wrap="nowrap" align="center" gap={10}>
                    <Text size="11px" fw={700} c="#495057" ta="center" w={42} miw={42}>
                        {calculateAge(birthDate, deathDate)}
                    </Text>

                    <Group wrap="nowrap" align="center" gap={4} style={{flex: 1, minWidth: 0}}>
                        <TextInput
                            value={birthDate}
                            placeholder="dd-MM-yyyy"
                            onChange={(event) => {
                                const next = normalizeDateInput(event.target.value);
                                setBirthDate(next);
                                updateData({birthDate: next || undefined});
                            }}
                            variant="unstyled"
                            leftSection={<IconCake size={10} stroke={1.8}/>}
                            leftSectionWidth={14}
                            classNames={{
                                input: 'nodrag nowheel'
                            }}
                            styles={{
                                root: {flex: '0 0 82px', minWidth: 82},
                                input: {fontSize: '10px', color: '#495057', padding: 0, paddingLeft: 16}
                            }}
                        />

                        <TextInput
                            value={deathDate}
                            placeholder="dd-MM-yyyy"
                            onChange={(event) => {
                                const next = normalizeDateInput(event.target.value);
                                setDeathDate(next);
                                updateData({deathDate: next || undefined, deceased: Boolean(next.trim())});
                            }}
                            variant="unstyled"
                            leftSection={<IconCross size={10} stroke={1.8}/>}
                            leftSectionWidth={14}
                            classNames={{
                                input: 'nodrag nowheel'
                            }}
                            styles={{
                                root: {flex: '0 0 82px', minWidth: 82},
                                input: {fontSize: '10px', color: '#495057', padding: 0, paddingLeft: 16}
                            }}
                        />
                    </Group>
                </Group>
            </Stack>
        </div>
    )

}

import React from "react";
import type {Person} from "@/core/domain/genogram.ts";
import type {Node, NodeProps} from '@xyflow/react';
import {useReactFlow} from '@xyflow/react';
import {IconCake, IconCross, IconGripVertical} from '@tabler/icons-react';
import {Box, Group, Stack, Text, TextInput, Textarea} from '@mantine/core';
import {SymbolIcon} from "@/core/ui/icons/SymbolIcons.tsx";
import type {GenogramEdge} from "@/features/diagram/types/edges.tsx";
import type {GenogramNode} from "@/features/diagram/types/nodes.ts";

import nodeClasses from './nodes.module.css';

type PersonNode = Node<Person, "person" | "pregnancy" | "loss" | "pet">;

const clampToLines = (value: string, maxLines = 3): string => value.split(/\r?\n/).slice(0, maxLines).join('\n');

const ISO_DATE_RE = /^(\d{4})-(\d{2})-(\d{2})$/;
const DISPLAY_DATE_RE = /^(\d{2})-(\d{2})-(\d{4})$/;

const normalizeDateInput = (value: string): string => {
    const digits = value.replace(/\D/g, '').slice(0, 8);
    if (digits.length <= 2) return digits;
    if (digits.length <= 4) return `${digits.slice(0, 2)}-${digits.slice(2)}`;
    return `${digits.slice(0, 2)}-${digits.slice(2, 4)}-${digits.slice(4)}`;
};

const toDisplayDate = (value?: string): string => {
    if (!value) return '';
    const trimmed = value.trim();
    const display = trimmed.match(DISPLAY_DATE_RE);
    if (display) return trimmed;

    const iso = trimmed.match(ISO_DATE_RE);
    if (!iso) return trimmed;
    return `${iso[3]}-${iso[2]}-${iso[1]}`;
};

const parseDate = (value?: string): Date | null => {
    if (!value) return null;
    const trimmed = value.trim();

    const display = trimmed.match(DISPLAY_DATE_RE);
    if (display) {
        const day = Number(display[1]);
        const month = Number(display[2]);
        const year = Number(display[3]);
        const date = new Date(year, month - 1, day);
        if (date.getFullYear() === year && date.getMonth() === month - 1 && date.getDate() === day) return date;
        return null;
    }

    const iso = trimmed.match(ISO_DATE_RE);
    if (iso) {
        const year = Number(iso[1]);
        const month = Number(iso[2]);
        const day = Number(iso[3]);
        const date = new Date(year, month - 1, day);
        if (date.getFullYear() === year && date.getMonth() === month - 1 && date.getDate() === day) return date;
    }

    return null;
};

const calculateAge = (birthDate?: string, deathDate?: string): string => {
    if (!birthDate) return '-';

    const birth = parseDate(birthDate);
    if (!birth) return '-';

    const end = deathDate ? parseDate(deathDate) : new Date();
    if (!end || end < birth) return '-';

    let years = end.getFullYear() - birth.getFullYear();
    const monthDelta = end.getMonth() - birth.getMonth();
    const dayDelta = end.getDate() - birth.getDate();

    if (monthDelta < 0 || (monthDelta === 0 && dayDelta < 0)) years -= 1;
    return `${Math.max(0, years)}`;
};

export const PersonNode: React.FC<NodeProps<PersonNode>> = ({id, data}) => {
    const {setNodes} = useReactFlow<GenogramNode, GenogramEdge>();
    const [name, setName] = React.useState(data.callSign ?? '');
    const [birthDate, setBirthDate] = React.useState(toDisplayDate(data.birthDate));
    const [deathDate, setDeathDate] = React.useState(toDisplayDate(data.deathDate));

    React.useEffect(() => {
        setName(data.callSign ?? '');
        setBirthDate(toDisplayDate(data.birthDate));
        setDeathDate(toDisplayDate(data.deathDate));
    }, [data.callSign, data.birthDate, data.deathDate]);

    const updateData = React.useCallback((patch: Partial<Person>) => {
        setNodes((currentNodes) => currentNodes.map((node) => {
            if (node.id !== id) return node;
            return {
                ...node,
                data: {
                    ...node.data,
                    ...patch
                }
            } as GenogramNode;
        }));
    }, [id, setNodes]);

    return (
        <div className={nodeClasses.card}>
            <Stack gap={2}>
                <Group wrap="nowrap" align="center" gap={10}>
                    <Box w={42} miw={42} style={{display: 'flex', justifyContent: 'flex-start'}}>
                        <div className={`${nodeClasses.dragHandle} drag-handle`} title="Drag node">
                            <IconGripVertical size={12} stroke={1.8}/>
                        </div>
                    </Box>
                </Group>

                {/* Grid: left col = symbol+age stacked, right col = name+dates stacked */}
                <div className={nodeClasses.contentGrid}>
                    {/* Left column */}
                    <div className={nodeClasses.leftCol}>
                        <SymbolIcon symbol={data.symbol} deceased={data.deceased} size={34}/>
                        <Text size="11px" fw={700} c="#495057" ta="center">
                            {calculateAge(birthDate, deathDate)}
                        </Text>
                    </div>

                    {/* Right column */}
                    <div className={nodeClasses.rightCol}>
                        <Textarea
                            className="nodrag nowheel"
                            value={name}
                            onChange={(event) => {
                                const next = clampToLines(event.target.value, 3);
                                setName(next);
                            }}
                            onBlur={() => updateData({callSign: name})}
                            placeholder="Name"
                            variant="unstyled"
                            rows={3}
                            autosize={false}
                            classNames={{input: 'nodrag nowheel'}}
                            styles={{
                                root: {width: '100%'},
                                input: {
                                    width: '100%',
                                    minHeight: '3.4em',
                                    fontSize: '14px',
                                    fontWeight: 600,
                                    lineHeight: 1.15,
                                    color: '#1f2937',
                                    margin: 0,
                                    padding: 0,
                                    resize: 'none'
                                }
                            }}
                        />

                        <Group wrap="nowrap" align="center" gap={4}>
                            <TextInput
                                className="nodrag nowheel"
                                value={birthDate}
                                placeholder="dd-MM-yyyy"
                                onChange={(event) => {
                                    const next = normalizeDateInput(event.target.value);
                                    setBirthDate(next);
                                    updateData({birthDate: next || undefined});
                                }}
                                variant="unstyled"
                                leftSection={<IconCake size={10} stroke={1.8}/>}
                                leftSectionWidth={14}
                                classNames={{input: 'nodrag nowheel'}}
                                styles={{
                                    root: {flex: '0 0 82px'},
                                    input: {fontSize: '10px', color: '#495057', padding: 0, paddingLeft: 16, userSelect: 'text'}
                                }}
                            />
                            <TextInput
                                className="nodrag nowheel"
                                value={deathDate}
                                placeholder="dd-MM-yyyy"
                                onChange={(event) => {
                                    const next = normalizeDateInput(event.target.value);
                                    setDeathDate(next);
                                    updateData({deathDate: next || undefined, deceased: Boolean(next.trim())});
                                }}
                                variant="unstyled"
                                leftSection={<IconCross size={10} stroke={1.8}/>}
                                leftSectionWidth={14}
                                classNames={{input: 'nodrag nowheel'}}
                                styles={{
                                    root: {flex: '0 0 82px'},
                                    input: {fontSize: '10px', color: '#495057', padding: 0, paddingLeft: 16, userSelect: 'text'}
                                }}
                            />
                        </Group>
                    </div>
                </div>
            </Stack>
        </div>
    )

}

.card {
    background: linear-gradient(160deg, #ffffff 0%, #eef2ff 100%);
    border: 1.5px solid #bfcbff;
    border-radius: 10px;
    box-shadow: 0 4px 16px rgba(15,23,42,0.10);
    padding: 18px 20px 18px 16px;
    width: 240px;
    height: 120px;
    box-sizing: border-box;
    display: grid;
    grid-template-columns: 42px 1fr 1fr;
    grid-template-rows: auto auto;
    column-gap: 10px;
    row-gap: 2px;
    position: relative;
    overflow: visible;
    transition: box-shadow 140ms ease, border-color 140ms ease;
    cursor: default;
}

.card {
    background: linear-gradient(160deg, #ffffff 0%, #eef2ff 100%);
    border: 1.5px solid #bfcbff;
    border-radius: 10px;
    box-shadow: 0 4px 16px rgba(15,23,42,0.10);
    padding: 8px;
    width: 240px;
    height: 120px;
    box-sizing: border-box;
    display: block;
    position: relative;
    overflow: hidden;
    transition: box-shadow 140ms ease, border-color 140ms ease;
    cursor: default;
}

.contentGrid {
    display: grid;
    grid-template-columns: 42px 1fr;
    gap: 8px;
    align-items: start;
}

.leftCol {
    display: flex;
    flex-direction: column;
    align-items: center;
    justify-content: flex-start;
    gap: 4px;
    height: 100%;
}

.rightCol {
    display: flex;
    flex-direction: column;
    gap: 2px;
    min-width: 0;
}

.dragHandle {
    width: 16px;
    height: 16px;
    display: inline-flex;
    align-items: center;
    justify-content: center;
    color: #6c757d;
    border-radius: 4px;
    cursor: grab;
}

.dragHandle:active {
    cursor: grabbing;
}
